import React from 'react';
import { useNavigate } from 'react-router-dom';
import './WelcomeScreen.css';

const WelcomeScreen = ({ config }) => {
  const navigate = useNavigate();
  const companyName = config?.companyName || 'Your Company';
  const logoUrl = config?.logoUrl || '/assets/logo.png';

  return (
    <div className="welcome-screen">
      <div className="welcome-container">
        <div className="welcome-header">
          {logoUrl && (
            <div className="logo-container">
              <img src={logoUrl} alt="Company Logo" className="company-logo" />
            </div>
          )}
          <h1 className="welcome-title">PortIQ</h1>
          <h2 className="company-name">Meeting Assistant</h2>
          <p className="welcome-subtitle">AI-Powered Meeting Intelligence</p>
        </div>

        <div className="welcome-actions">
          <button 
            className="action-btn primary"
            onClick={() => navigate('/meetings')}
          >
            <span className="btn-text">Start Meeting Assistant</span>
          </button>
        </div>
      </div>

      <div className="branding-footer">
        PortIQ Meeting Assistant
      </div>
    </div>
  );
};

export default WelcomeScreen;
